 14→interface ClaudePromptResult {
 15→  toolsCalled: string[];
 16→  logOutput: string;
 17→}
 18→
 19→/**
 20→ * Execute a prompt via Claude Code CLI and parse MCP tool output.
 21→ */
 22→async function executeClaudePrompt(
 23→  prompt: string,
 24→  timeout: number = PROVISION_TIMEOUT
 25→): Promise<ClaudePromptResult> {
 26→  return new Promise((resolve, reject) => {
 27→    const projectRoot = process.cwd();
 28→    const mcpConfigPath = path.join(projectRoot, '.mcp.json');
 29→
 30→    const args = [
 31→      '--print',
 32→      prompt,
 33→      '--mcp-config', mcpConfigPath,
 34→      '--allowedTools', 'mcp__mittwald__*',
 35→      '--output-format', 'stream-json',
 36→      '--verbose'
 37→    ];
 38→
 39→    const child = spawn('claude', args, {
 40→      cwd: projectRoot,
 41→      stdio: ['ignore', 'pipe', 'pipe'],
 42→      timeout,
 43→      env: {
 44→        ...process.env,
 45→        HOME: process.env.HOME,
 46→        PATH: process.env.PATH
 47→      }
 48→    });
 49→
 50→    let stdout = '';
 51→    let stderr = '';
 52→
 53→    child.stdout?.on('data', (data) => {
 54→      stdout += data.toString();
 55→    });
 56→
 57→    child.stderr?.on('data', (data) => {
 58→      stderr += data.toString();
 59→    });
 60→
 61→    child.on('close', (code) => {
 62→      if (code === 0) {
 63→        const toolsCalled = parseToolCallsFromOutput(stdout);
 64→        resolve({ toolsCalled, logOutput: stdout });
 65→      } else {
 66→        reject(new Error(`Claude CLI exited with code ${code}: ${stderr}`));
 67→      }
 68→    });
 69→
 70→    child.on('error', (error) => {
 71→      reject(new Error(`Failed to spawn Claude CLI: ${error.message}`));
 72→    });
 73→
 74→    setTimeout(() => {
 75→      if (!child.killed) {
 76→        child.kill();
 77→        reject(new Error(`Provisioning timeout (${timeout}ms)`));
 78→      }
 79→    }, timeout);
 80→  });
 81→}
