 83→/**
 84→ * Parse tool calls from Claude CLI output.
 85→ */
 86→function parseToolCallsFromOutput(output: string): string[] {
 87→  const tools: string[] = [];
 88→  const lines = output.split('\n');
 89→
 90→  for (const line of lines) {
 91→    if (!line.trim()) continue;
 92→
 93→    try {
 94→      const json = JSON.parse(line);
 95→      if (json.type === 'assistant' && json.message?.content) {
 96→        for (const content of json.message.content) {
 97→          if (content.type === 'tool_use' && content.name) {
 98→            tools.push(content.name);
 99→          }
100→        }
101→      }
102→    } catch {
103→      // Skip non-JSON lines
104→    }
105→  }
106→
107→  return tools;
108→}
