110→/**
111→ * Extract resource ID from MCP tool output.
112→ * Looks for patterns like "id": "p-xxxxx" in JSON output.
113→ */
114→function extractResourceId(output: string, resourceType: string): string {
115→  // Try to find ID in JSON format first
116→  const idPattern = /"id"\s*:\s*"([a-z]+-[a-z0-9]+)"/;
117→  const match = output.match(idPattern);
118→
119→  if (match) {
120→    return match[1];
121→  }
122→
123→  // Fallback: look for resource-specific patterns
124→  const patterns: Record<string, RegExp> = {
125→    project: /project\s+([a-z]+-[a-z0-9]+)/i,
126→    mysql: /database\s+([a-z]+-[a-z0-9]+)/i,
127→    redis: /redis\s+([a-z]+-[a-z0-9]+)/i,
128→    app: /app\s+([a-z]+-[a-z0-9]+)/i,
129→    domain: /domain\s+([a-z]+-[a-z0-9]+)/i,
130→    virtualhost: /virtualhost\s+([a-z]+-[a-z0-9]+)/i,
131→  };
132→
133→  const pattern = patterns[resourceType];
134→  if (pattern) {
135→    const fallbackMatch = output.match(pattern);
136→    if (fallbackMatch) {
137→      return fallbackMatch[1];
138→    }
139→  }
140→
141→  throw new Error(`Failed to extract ${resourceType} ID from output`);
142→}
